const item = $input.first().json;

const firstName   = String(item['First Name']      ?? '').trim();
const lastName    = String(item['Last Name']       ?? '').trim();
const jobTitle    = String(item['Job Title']       ?? '').trim();
const studioRaw   = String(item['Studio']          ?? '').trim();
const empId       = String(item['EMP ID']          ?? '').trim();
const phoneExt    = String(item['Phone Extension'] ?? '').trim();
const credentials = String(item['Credentials']     ?? '').trim();

if (!firstName) throw new Error('First Name is required.');
if (!lastName)  throw new Error('Last Name is required.');
if (!studioRaw) throw new Error('Studio selection is required.');

// Auto-detect delimiter
const delimiter = studioRaw.includes(' ~~ ') ? ' ~~ ' : ' | ';
const parts     = studioRaw.split(delimiter).map(s => s.trim());
const labelPart = parts[0] ?? '';
const street    = parts[1] ?? '';
const state     = parts[3] ?? '';
const zip       = parts[4] ?? '';
const phone     = parts[5] ?? '';

const dashIdx = labelPart.indexOf(' \u2014 ');
const company = dashIdx !== -1 ? labelPart.substring(0, dashIdx).trim() : labelPart.trim();
const city    = dashIdx !== -1 ? labelPart.substring(dashIdx + 3).trim() : '';

if (!company) throw new Error(`Could not parse company from Studio value: ${studioRaw}`);
if (!city)    throw new Error(`Could not parse city from Studio value: ${studioRaw}`);

const ouCity             = city.replace(/[-\s]/g, '');
const sAMAccountName     = (firstName.charAt(0) + lastName).toLowerCase();
const displayName        = `${firstName} ${lastName}`;
const cn                 = displayName;
const dn                 = `CN=${cn},OU=${ouCity},OU=${company},OU=MGA USERS,DC=MGA,DC=com`;
const targetOU           = `OU=${ouCity},OU=${company},OU=MGA USERS,DC=MGA,DC=com`;
const userPrincipalName  = `${sAMAccountName}@michaelgraves.com`;
const mail               = `${sAMAccountName}@michaelgraves.com`;

const optionalFields = {};
if (empId)       optionalFields.pager   = empId;
if (phoneExt)    optionalFields.ipPhone  = phoneExt;
if (credentials) optionalFields.info     = credentials;

const homeFolderSelection = item['Home Folder (Z: Drive)'];
const setupHomeFolder = Array.isArray(homeFolderSelection) ? homeFolderSelection.length > 0 : !!homeFolderSelection;
if (setupHomeFolder) {
  const bs = String.fromCharCode(92);
  optionalFields.homeDrive = 'Z:';
  optionalFields.homeDirectory = bs + bs + 'mga.com' + bs + 'mga_files' + bs + 'scans' + bs + sAMAccountName;
}

const selectedGroups = Array.isArray(item['Groups']) ? item['Groups'] : (item['Groups'] ? [item['Groups']] : []);
const groupDns = selectedGroups.map(g => `CN=${g},OU=Security Groups,DC=MGA,DC=com`);

// HTML completion pages
const successHtml = `<div style="font-family: 'Open Sans', sans-serif; max-width: 480px; margin: 40px auto; padding: 32px; background: #fff; border-radius: 8px; box-shadow: 0 4px 16px rgba(99,77,255,0.08); border-top: 4px solid #38a169;">
  <div style="display:flex; align-items:center; margin-bottom:16px;">
    <span style="font-size:28px; margin-right:12px;">\u2705</span>
    <h2 style="margin:0; color:#276749; font-size:20px;">User Created Successfully</h2>
  </div>
  <p style="color:#555; font-size:14px; line-height:1.6; margin:0 0 12px;">
    The Active Directory account <strong style="color:#2d3748;">${sAMAccountName}</strong> has been created.
  </p>
  <p style="color:#555; font-size:14px; line-height:1.6; margin:0;">
    The user can log in with their temporary password and will be prompted to change it on first sign-in.
  </p>
</div>`;

const updatedHtml = `<div style="font-family: 'Open Sans', sans-serif; max-width: 480px; margin: 40px auto; padding: 32px; background: #fff; border-radius: 8px; box-shadow: 0 4px 16px rgba(99,77,255,0.08); border-top: 4px solid #3182ce;">
  <div style="display:flex; align-items:center; margin-bottom:16px;">
    <span style="font-size:28px; margin-right:12px;">\ud83d\udd04</span>
    <h2 style="margin:0; color:#2b6cb0; font-size:20px;">User Updated Successfully</h2>
  </div>
  <p style="color:#555; font-size:14px; line-height:1.6; margin:0 0 12px;">
    The Active Directory account <strong style="color:#2d3748;">${sAMAccountName}</strong> has been updated and re-enabled.
  </p>
  <p style="color:#555; font-size:14px; line-height:1.6; margin:0;">
    The user can log in with their temporary password and will be prompted to change it on first sign-in.
  </p>
</div>`;

return [{
  json: {
    dn,
    targetOU,
    sAMAccountName,
    displayName,
    givenName: firstName,
    sn: lastName,
    cn,
    title: jobTitle,
    company,
    streetAddress: street,
    l: city,
    st: state,
    postalCode: zip,
    telephoneNumber: phone,
    userPrincipalName,
    mail,
    objectClass: 'user',
    userAccountControl: '514',
    successHtml,
    updatedHtml,
    groupDns,
    ...optionalFields
  }
}];

const adAttrs = $('Code: Build AD user attributes').first().json;
const searchResults = $input.all();

// alwaysOutputData=false on LDAP means 0 items = not found, 1+ items = found
// continueOnFail=true means errors also pass through as items with error info
const firstJson = searchResults.length > 0 ? searchResults[0].json : {};
const userExists = searchResults.length > 0 && !!firstJson.dn;

let existingDn = null;
let userAccountControl = null;
let isEnabled = false;

if (userExists) {
  existingDn = searchResults[0].json.dn || searchResults[0].json.distinguishedName || null;
  userAccountControl = parseInt(searchResults[0].json.userAccountControl ?? '514', 10);
  // UAC bit 2 (value 2) = account disabled
  isEnabled = (userAccountControl & 2) === 0;
}

console.log(`User exists: ${userExists}, DN: ${existingDn}, UAC: ${userAccountControl}, Enabled: ${isEnabled}`);

return [{
  json: {
    ...adAttrs,
    userExists,
    existingDn,
    userAccountControl: userAccountControl ?? 514,
    isEnabled
  }
}];

const adAttrs = $('Code: Build AD user attributes').first().json;

const plainPassword = `MGAtemp${new Date().getFullYear()}`;

function encodePassword(password) {
  let encoded = '';
  const quoted = '"' + password + '"';
  for (let i = 0; i < quoted.length; i++) {
    encoded += String.fromCharCode(
      quoted.charCodeAt(i) & 0xFF,
      (quoted.charCodeAt(i) >>> 8) & 0xFF
    );
  }
  return encoded;
}

return [{ json: { ...adAttrs, unicodePwd: encodePassword(plainPassword) } }];

const adAttrs = $('Code: Build AD user attributes').first().json;
const existing = $('LDAP: Get current DN').first().json;

function valueOrExisting(submitted, existingVal) {
  const v = String(submitted ?? '').trim();
  if (v !== '') return v;
  const e = String(existingVal ?? '').trim();
  return e !== '' ? e : ' ';
}

const finalTitle           = valueOrExisting(adAttrs.title, existing.title);
const finalCompany         = valueOrExisting(adAttrs.company, existing.company);
const finalStreetAddress   = valueOrExisting(adAttrs.streetAddress, existing.streetAddress);
const finalL               = valueOrExisting(adAttrs.l, existing.l);
const finalSt              = valueOrExisting(adAttrs.st, existing.st);
const finalPostalCode      = valueOrExisting(adAttrs.postalCode, existing.postalCode);
const finalTelephoneNumber = valueOrExisting(adAttrs.telephoneNumber, existing.telephoneNumber);
const finalMail            = valueOrExisting(adAttrs.mail, existing.mail);

// Optional fields: if submitted -> replace, if blank -> delete
const optionalFields = [
  { id: 'pager',   value: String(adAttrs.pager   ?? '').trim() },
  { id: 'ipPhone', value: String(adAttrs.ipPhone  ?? '').trim() },
  { id: 'info',    value: String(adAttrs.info     ?? '').trim() },
  { id: 'homeDrive',     value: String(adAttrs.homeDrive     ?? '').trim() },
  { id: 'homeDirectory', value: String(adAttrs.homeDirectory ?? '').trim() },
];

const optionalReplace = optionalFields.filter(f => f.value !== '');
const optionalDelete  = optionalFields.filter(f => f.value === '').map(f => f.id);
const hasOptional     = optionalFields.length > 0; // always true — always process optional fields

return [{ json: {
  ...adAttrs,
  finalTitle, finalCompany, finalStreetAddress, finalL, finalSt,
  finalPostalCode, finalTelephoneNumber, finalMail,
  optionalReplace, optionalDelete, hasOptional
} }];

const adAttrs = $('Code: Build AD user attributes').first().json;
const plainPassword = `MGAtemp${new Date().getFullYear()}`;
function encodePassword(password) {
  let encoded = '';
  const quoted = '"' + password + '"';
  for (let i = 0; i < quoted.length; i++) {
    encoded += String.fromCharCode(quoted.charCodeAt(i) & 0xFF, (quoted.charCodeAt(i) >>> 8) & 0xFF);
  }
  return encoded;
}
return [{ json: { ...adAttrs, unicodePwd: encodePassword(plainPassword) } }];

const a = $('Code: Build AD user attributes').first().json;
const userDn = a.dn;
const desired = new Set(a.groupDns || []);
const current = new Set($input.all().map(item => `CN=${item.json.cn},OU=Security Groups,DC=MGA,DC=com`));

const actions = [];
for (const dn of desired) if (!current.has(dn)) actions.push({ groupDn: dn, action: 'add', userDn });
for (const dn of current) if (!desired.has(dn)) actions.push({ groupDn: dn, action: 'remove', userDn });

if (actions.length === 0) return [{ json: { action: 'noop', userDn } }];
return actions.map(item => ({ json: item }));
